    56Ôćĺ	if host := os.Getenv("SANDCASTLE_HOST"); host != "" {
    57Ôćĺ		// 1. Alias match
    58Ôćĺ		if srv, ok := cfg.Servers[host]; ok {
    59Ôćĺ			logVerbose("server (SANDCASTLE_HOST alias): %s (%s)", host, srv.URL)
