   109Ôćĺfunc (c *Client) do(method, path string, body any, result any) error {
   110Ôćĺ	var bodyReader io.Reader
   111Ôćĺ	var reqData []byte
   112Ôćĺ	if body != nil {
   113Ôćĺ		var err error
   114Ôćĺ		reqData, err = json.Marshal(body)
   115Ôćĺ		if err != nil {
   116Ôćĺ			return fmt.Errorf("marshaling request: %w", err)
   117Ôćĺ		}
   118Ôćĺ		bodyReader = bytes.NewReader(reqData)
   119Ôćĺ	}
   120Ôćĺ
   121Ôćĺ	logVerbose("Ôćĺ %s %s%s", method, c.BaseURL, path)
   122Ôćĺ	if len(reqData) > 0 {
   123Ôćĺ		logVerbose("  request: %s", string(reqData))
   124Ôćĺ	}
   125Ôćĺ
   126Ôćĺ	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
   127Ôćĺ	if err != nil {
   128Ôćĺ		return fmt.Errorf("creating request: %w", err)
   129Ôćĺ	}
   130Ôćĺ
   131Ôćĺ	req.Header.Set("Content-Type", "application/json")
   132Ôćĺ	if c.Token != "" {
   133Ôćĺ		req.Header.Set("Authorization", "Bearer "+c.Token)
   134Ôćĺ	}
   135Ôćĺ
   136Ôćĺ	resp, err := c.HTTPClient.Do(req)
   137Ôćĺ	if err != nil {
   138Ôćĺ		return fmt.Errorf("request failed: %w", err)
   139Ôćĺ	}
   140Ôćĺ	defer resp.Body.Close()
   141Ôćĺ
   142Ôćĺ	respBody, err := io.ReadAll(resp.Body)
   143Ôćĺ	if err != nil {
   144Ôćĺ		return fmt.Errorf("reading response: %w", err)
   145Ôćĺ	}
   146Ôćĺ
   147Ôćĺ	logVerbose("ÔćÉ %d (%d bytes)", resp.StatusCode, len(respBody))
   148Ôćĺ	if len(respBody) > 0 {
   149Ôćĺ		logVerbose("  response: %s", string(respBody))
   150Ôćĺ	}
   151Ôćĺ
   152Ôćĺ	if resp.StatusCode >= 400 {
   153Ôćĺ		var apiErr APIError
   154Ôćĺ		if json.Unmarshal(respBody, &apiErr) == nil && apiErr.Error != "" {
   155Ôćĺ			return fmt.Errorf("API error (%d): %s", resp.StatusCode, apiErr.Error)
   156Ôćĺ		}
   157Ôćĺ		return fmt.Errorf("API error (%d): %s", resp.StatusCode, string(respBody))
   158Ôćĺ	}
   159Ôćĺ
   160Ôćĺ	if result != nil {
   161Ôćĺ		if err := json.Unmarshal(respBody, result); err != nil {
   162Ôćĺ			return fmt.Errorf("parsing response: %w", err)
   163Ôćĺ		}
   164Ôćĺ	}
   165Ôćĺ	return nil
   166Ôćĺ}
